-- Name: capt_loc_dbmin; Type: VIEW; Schema: public; Owner: eleaweber
--

CREATE VIEW public.capt_loc_dbmin AS
 SELECT cl.id_capteur_gen,
    cl.id_loc,
    cl.date_debut,
    cl.date_fin,
    c.id_capteur,
    c.date_activation,
    c.num_colonne,
    c.id_instrument,
    im.id_instrument AS instrument_id_instrument,
    im.num_instrument
   FROM ((public.capteur_localise cl
     JOIN public.capteur c ON ((c.id_capteur = cl.id_capteur_gen)))
     JOIN public.instrument_mesure im ON ((im.id_instrument = c.id_instrument)))
  WHERE ((lower((im.num_instrument)::text) = lower('HOBO_n°36'::text)) AND (cl.date_debut > to_timestamp('2024-03-21 15:45:10'::text, 'YYYY-MM-DD HH24:MI:SS'::text)) AND (cl.date_debut = ( SELECT min(cl2.date_debut) AS min
           FROM (public.capteur_localise cl2
             JOIN public.capteur c2 ON ((c2.id_capteur = cl2.id_capteur_gen)))
          WHERE ((c2.id_instrument = im.id_instrument) AND (cl2.date_debut > to_timestamp('2024-03-21 15:45:10'::text, 'YYYY-MM-DD HH24:MI:SS'::text))))));


